solutions.python:
class Solution:
    def toLowerCase(self, s: str) -> str:
        return "".join(ch.lower() for ch in s)

solutions.cpp:
class Solution {
public:
    string toLowerCase(string s) {
        for (char& c : s)
            if (c >= 'A' && c <= 'Z') c += 32;
        return s;
    }
};

